package com.example.myapp

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity

class DeepLinkActivity : AppCompatActivity() {

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        handleDeepLink(intent)
        finish()
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        handleDeepLink(intent)
        finish()
    }

    private fun handleDeepLink(incomingIntent: Intent?) {
        val uri = incomingIntent?.data ?: return

        when (uri.host?.lowercase()) {
            "profile" -> navigateToProfile(uri)
            "payment" -> navigateToPayment(uri)
            else      -> launchDefault()
        }
    }

    private fun navigateToProfile(uri: Uri) {
        val userId = uri.pathSegments.firstOrNull() ?: return
        val intent = Intent(this, ProfileActivity::class.java).apply {
            putExtra(ProfileActivity.EXTRA_USER_ID, userId)
        }
        startActivity(intent)
    }

    private fun navigateToPayment(uri: Uri) {
        when (uri.pathSegments.firstOrNull()?.lowercase()) {
            "confirm" -> {
                val intent = Intent(this, PaymentConfirmationActivity::class.java)
                startActivity(intent)
            }
            else -> launchDefault()
        }
    }

    private fun launchDefault() {
        startActivity(Intent(this, MainActivity::class.java))
    }
}


